function loadSolarIcons(o={}){const u=o.url||'https://cdn.jsdelivr.net/gh/helloanaroul/icons@refs/heads/main/icons.json',P='[ICONS]',E=document.querySelectorAll('i[name], i[class]');if(!E.length){console.info(`${P} No <i> elements found. Skipping icon load.`);return;}console.group(`${P} Initializing...`);console.groupCollapsed('%c[ICONS] Developer Information','color:#64748b;font-size:10px;font-weight:normal;');console.log('%c  Developer       : Anaroul Hasan\n  GitHub          : github.com/helloanaroul/icons\n  Usage           : https://github.com/helloanaroul/icons/blob/main/README.md\n  jsdelivr        : https://cdn.jsdelivr.net/gh/helloanaroul/icons@refs/heads/main/icons.js\n  Icon Webpage    : https://icones.js.org/collection/solar','color:#E87F24;font-size:10px;line-height:1.8;');console.groupEnd();console.groupCollapsed('%c[ICONS] Usage Examples','color:#64748b;font-size:10px;font-weight:normal;');console.log('%c  <!-- Method 1: name attribute -->\n  <i name="home-bold"></i>\n\n  <!-- Method 2: prefix + class -->\n  <i class="solar-home-bold"></i>\n\n  <!-- Method 3: exact icon key -->\n  <i class="home-bold"></i>','color:#7dd3fc;font-family:monospace;font-size:11px;line-height:1.9;');console.groupEnd();console.info(`${P} Found ${E.length} potential icon element(s).`);console.time(`${P} Total load time`);console.log(`${P} Fetching: ${u}`);fetch(u).then(r=>{if(!r.ok)throw new Error(`HTTP ${r.status} — ${r.statusText}`);console.log(`${P} icons.json loaded (${r.status} OK)`);return r.json();}).then(d=>{const px=d.prefix||'solar',ic=d.icons||{},al=d.aliases||{},dw=d.width||24,dh=d.height||24;console.log(`${P} Parsed — ${Object.keys(ic).length} icons, ${Object.keys(al).length} aliases, prefix:"${px}"`);let rv=0,sk=0,nf=0;E.forEach((el,i)=>{let n=el.getAttribute('name');if(!n){for(const c of el.classList){if(c.startsWith(`${px}-`)){n=c.substring(px.length+1);break;}}}if(!n){for(const c of el.classList){if(ic[c]||al[c]){n=c;break;}}}if(!n){console.warn(`${P} [${i}] Skipped — no icon name.`,el);sk++;return;}let rn=n;if(al[rn]){console.debug(`${P} [${i}] Alias "${n}" → "${al[n].parent}"`);rn=al[rn].parent;}if(!ic[rn]){console.warn(`${P} [${i}] Not found: "${n}"${rn!==n?` (resolved:"${rn}")`:''}`);nf++;return;}const{width:w=dw,height:h=dh,body:b}=ic[rn];el.innerHTML=`<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${w} ${h}" width="1em" height="1em" style="vertical-align:-0.125em;" aria-hidden="true">${b}</svg>`;el.setAttribute('aria-label',n);el.setAttribute('role','img');console.debug(`${P} [${i}] ✓ "${n}"`);rv++;});console.log(`%c${P} Done — ✓ ${rv} rendered | ⚠ ${nf} not found | ⊘ ${sk} skipped`,'color:#22c55e;font-weight:bold;');console.timeEnd(`${P} Total load time`);console.groupEnd();}).catch(e=>{console.error(`${P} Failed to load "${u}":`,e);console.timeEnd(`${P} Total load time`);console.groupEnd();});}
document.readyState==='loading'?document.addEventListener('DOMContentLoaded',()=>loadSolarIcons()):loadSolarIcons();
